use std::borrow::Cow;

fn process_data(input: Cow<str>) -> Result<String, &'static str>
{
    if input.is_empty() {
        return Err("Input cannot be empty");
    }

    let result = format!("Processed: {}", input);
    Ok(result)
}

fn main() {
    // Case 1: Input is already owned (String)
    let owned_str = String::from("Hello World");
    match process_data(Cow::Owned(owned_str.into())) {
        Ok(s) => println!("Success with Owned input: {}", s),
        Err(e) => println!("Error: {}", e),
    }

    // Case 2: Input is borrowed (literal &str)
    let borrowed_str = "Another Test";
    match process_data(Cow::Borrowed(borrowed_str)) {
        Ok(s) => println!("Success with Borrowed input: {}", s),
        Err(e) => println!("Error: {}", e),
    }

    // Case 3: Empty input test
    match process_data(Cow::Borrowed("")) {
        Ok(s) => println!("Success with Empty input: {}", s),
        Err(e) => println!("Error on empty input: {}", e),
    }
}

