use std::borrow::Cow;

fn process_cow(input: Cow<'_, str>) -> Result<Cow<'_, str>, String> {
    if input.is_empty() {
        return Err("Input cannot be empty".to_string());
    }

    let processed = format!("Processed: {}", input);
    Ok(Cow::Owned(processed))
}

fn main() {
    let slice1 = "hello";
    let result1 = process_cow(Cow::Borrowed(slice1));
    println!("Result 1: {:?}", result1); 

    let owned_str = String::from("world");
    let result2 = process_cow(Cow::Owned(owned_str));
    println!("Result 2: {:?}", result2);
}

