use std::borrow::Cow;

fn process_input(s: Cow<str>) -> String {
    if s.is_empty() {
        String::from("")
    } else if s.starts_with("error") {
        format!("Processed error message: {}", &s[5..].to_uppercase())
    } else {
        format!("Successfully processed input: {}", &s)
    }
}

fn main() {
    let owned_str = String::from("hello world");
    let borrowed_slice = "another test";

    let result1 = process_input(Cow::Owned(owned_str.into()));
    println!("Result 1: {}", result1);

    let result2 = process_input(Cow::Borrowed(borrowed_slice));
    println!("Result 2: {}", result2);
}
